def calculate_total(items, tax_rate, discount, shipping, handling):
    total = 0
    for item in items:
        if item['type'] == 'A':
            if item['quantity'] > 10:
                total = total + item['price'] * item['quantity'] * 0.9
            else:
                if item['price'] > 100:
                    total = total + item['price'] * item['quantity'] * 0.95
                else:
                    total = total + item['price'] * item['quantity']
        elif item['type'] == 'B':
            if item['quantity'] > 5:
                total = total + item['price'] * item['quantity'] * 0.85
            else:
                total = total + item['price'] * item['quantity']
        elif item['type'] == 'C':
            total = total + item['price'] * item['quantity'] * 1.1
        else:
            total = total + item['price'] * item['quantity']

    # 应用税率
    total = total * (1 + tax_rate)

    # 应用折扣
    total = total - discount

    # 加上运费
    total = total + shipping

    # 加上处理费
    total = total + handling

    return total


