def process_data(data):
    result = []
    for item in data:
        if item['status'] == 'active':
            if item['type'] == 'premium':
                if item['level'] > 5:
                    if item['score'] > 90:
                        result.append({'status': 'approved', 'bonus': 100})
                    else:
                        result.append({'status': 'approved', 'bonus': 50})
                else:
                    result.append({'status': 'approved', 'bonus': 25})
            else:
                result.append({'status': 'approved', 'bonus': 10})
        else:
            result.append({'status': 'rejected'})
    return result


